// Competency: httpsts-security-header-policy.
// Case 4116: burst intake service near its event-loop and queue limits.
// Operating constraint: prove cleanup before the service deadline expires.
// Changed case: saturate one tenant budget while another tenant remains serviceable.
function evidence_httpsts_security_header_policy_7fr4rh(originAllowed: boolean, safeMethod: boolean, csrfMatches: boolean, sameSite: boolean): { share: boolean; mutate: boolean; reason: string } {
  const share = originAllowed;
  if (safeMethod) return { share, mutate: false, reason: "safe-method" };
  const mutate = csrfMatches && sameSite;
  return { share, mutate, reason: mutate ? "csrf-defended" : "csrf-denied" };
}
